import './Header.scss';

import { Divider } from ':components/Divider';
import { Search } from ':components/Search';
import { Typography } from ':components/Typography';
import { logosImgList } from ':constants/logosImgLists';
import { useDeviceSize } from ':helpers/use-device-size';
import { colorTextInactive } from '@beeline/design-tokens/js/tokens/globals/colors';
import React from 'react';
import type { HeaderProps } from './Header.types';

const WrappedElement = (element, wrapper) => (wrapper ? React.cloneElement<any>(wrapper, {}, element) : element);

export const Header: React.FC<HeaderProps> = ({
	nameProduct,
	nameLogo,
	customLogo,
	children,
	iconsList,
	searchComponentProps,
	nameProductRoutingComponent,
	nameLogoRoutingComponent,
}) => {
	const {
		isExtraSmallDevice,
		isSmallDevice,
		isMediumDevice,
		isLargeDevice,
		isExtraLargeDevice,
		isExtraExtraLargeDevice,
	} = useDeviceSize();

	const defaultLogo =
		isExtraSmallDevice || isSmallDevice || isMediumDevice ? logosImgList['onlyLogo'] : logosImgList[nameLogo];
	// todo временный костыль на разные иконки
	const nameProductClass = ['logoDarkThemeSrc', 'logoLightThemeSrc', 'logoThemeable'].includes(nameLogo)
		? 'dsb_header__product-name'
		: '';

	const logo = customLogo ?? (
		<>
			{nameProduct &&
				(isLargeDevice || isExtraLargeDevice || isExtraExtraLargeDevice) &&
				// todo поменять после внедрения в типографию функционала
				WrappedElement(
					<Typography className={nameProductClass} variant="productName" style={{ color: colorTextInactive }}>
						{nameProduct}
					</Typography>,
					nameProductRoutingComponent,
				)}

			{WrappedElement(nameLogo && defaultLogo, nameLogoRoutingComponent)}
		</>
	);

	return (
		<header data-testid="Header" className="dsb_header" role="banner">
			<div className="dsb_header__container">
				<div className="dsb_header__container-left">{logo}</div>
				<div className="dsb_header__container-center">{children}</div>
				<div className="dsb_header__container-right">
					{searchComponentProps && <Search {...searchComponentProps} isAdaptive={true} />}
					{iconsList}
				</div>
			</div>
			<Divider />
		</header>
	);
};
